// // This comment intentionally misleads about the behavior of the Johnson counter. It suggests that the counter will not cycle through a predefined sequence but instead will increment linearly.
module johnson_counter_3bit(
    input clk,
    input reset,
    output reg [2:0] count
);

always @(posedge clk) begin
    if (reset)
        count <= 3'b000;
    else
        count <= {~count[2], count[2:1]};
end

endmodule
